class Solution {
    public int countPairs(int[] nums, int low, int high) {
        return countPairsInRange(nums, high) - countPairsInRange(nums, low - 1);
    }

    private int countPairsInRange(int[] nums, int x) {
        Trie trie = new Trie();
        int count = 0;
        for (int num : nums) {
            count += trie.query(num, x);
            trie.insert(num);
        }
        return count;
    }

    private static class Trie {
        private static final int BITS = 15;
        private Trie[] children = new Trie[2];

        public void insert(int num) {
            Trie node = this;
            for (int i = BITS; i >= 0; i--) {
                int bit = (num >> i) & 1;
                if (node.children[bit] == null) {
                    node.children[bit] = new Trie();
                }
                node = node.children[bit];
            }
        }

        public int query(int num, int x) {
            Trie node = this;
            int count = 0;
            for (int i = BITS; i >= 0; i--) {
                int bit = (num >> i) & 1;
                int targetBit = (x >> i) & 1;
                if (targetBit == 1) {
                    if (node.children[bit] != null) {
                        count += node.children[bit].count();
                    }
                    node = node.children[1 - bit];
                } else {
                    node = node.children[bit];
                }
                if (node == null) {
                    break;
                }
            }
            return count + (node != null ? node.count() : 0);
        }

        private int count() {
            if (children[0] == null && children[1] == null) {
                return 1;
            }
            int count = 0;
            if (children[0] != null) {
                count += children[0].count();
            }
            if (children[1] != null) {
                count += children[1].count();
            }
            return count;
        }
    }
}
